const express = require('express');
const { createProxyMiddleware } = require('http-proxy-middleware');

const app = express();
const PORT = 3000;

// Prembly API Credentials from environment variables
const PREMBLY_APP_ID = process.env.PREMBLY_APP_ID;
const PREMBLY_API_KEY = process.env.PREMBLY_API_KEY;

// Proxy configuration
const premblyProxy = createProxyMiddleware({
  target: 'https://api.prembly.com',
  changeOrigin: true,
  pathRewrite: {
    '^/api/prembly': '', // remove /api/prembly from the request path
  },
  onProxyReq: (proxyReq, req, res) => {
    // Inject Prembly credentials into headers
    if (PREMBLY_APP_ID) {
      proxyReq.setHeader('app-id', PREMBLY_APP_ID);
    }
    if (PREMBLY_API_KEY) {
      proxyReq.setHeader('x-api-key', PREMBLY_API_KEY);
    }

    // If express.json() or express.urlencoded() was used, we would need to restream the body here.
    // Since we are not using them globally, http-proxy-middleware will handle the body automatically.
  },
  onError: (err, req, res) => {
    console.error('Proxy Error:', err);
    res.status(500).send('Proxy Error');
  }
});

// Apply proxy to /api/prembly/*
app.use('/api/prembly', premblyProxy);

app.listen(PORT, () => {
  console.log(`Proxy server listening on port ${PORT}`);
});

